insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:3-1-role-of-human-resources:match:810480b6', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Functions”?", "options": ["Rules imposed on businesses by the government that control how they employ and manage workers", "When a business reduces layers of management — changing HR needs as some roles are made redundant and others take on more responsibility", "Different types of work that need to be done in a business — including production, finance, marketing, and HR", "The idea that a decision in one area of a business (e.g. production) affects other areas (e.g. HR needs)"]}'::jsonb, '{"answer": 2, "explain": "“Functions” means: Different types of work that need to be done in a business — including production, finance, marketing, and HR"}'::jsonb),
('business:3-1-role-of-human-resources:match:c629d1dd', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Regulations”?", "options": ["When a business reduces layers of management — changing HR needs as some roles are made redundant and others take on more responsibility", "The idea that a decision in one area of a business (e.g. production) affects other areas (e.g. HR needs)", "Rules imposed on businesses by the government that control how they employ and manage workers", "The people who do the work for a business — including owners, employees, and contractors"]}'::jsonb, '{"answer": 2, "explain": "“Regulations” means: Rules imposed on businesses by the government that control how they employ and manage workers"}'::jsonb),
('business:3-1-role-of-human-resources:match:20a3f593', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Delayering (HR context)”?", "options": ["The idea that a decision in one area of a business (e.g. production) affects other areas (e.g. HR needs)", "When a business reduces layers of management — changing HR needs as some roles are made redundant and others take on more responsibility", "The people who do the work for a business — including owners, employees, and contractors", "A plan detailing the workers a business needs — how many, full- or part-time, the skills they should have, and when they will work"]}'::jsonb, '{"answer": 1, "explain": "“Delayering (HR context)” means: When a business reduces layers of management — changing HR needs as some roles are made redundant and others take on more responsibility"}'::jsonb),
('business:3-1-role-of-human-resources:match:cd2f93b6', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interdependent nature of business”?", "options": ["The people who do the work for a business — including owners, employees, and contractors", "A plan detailing the workers a business needs — how many, full- or part-time, the skills they should have, and when they will work", "The idea that a decision in one area of a business (e.g. production) affects other areas (e.g. HR needs)", "The activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed"]}'::jsonb, '{"answer": 2, "explain": "“Interdependent nature of business” means: The idea that a decision in one area of a business (e.g. production) affects other areas (e.g. HR needs)"}'::jsonb),
('business:3-2-organisational-structures:exam:fb508a68', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q1", "question": "The business made a net profit of: [1 mark]", "options": ["A — £3 million", "B — £16.5 million", "C — £1636.5 million", "D — £1650 million"], "caseStudy": "In 2023 a business sold 22 million items at an average price of £0.75 per item. Its total costs for the year were £13.5 million.", "hint": "First calculate total revenue (price × quantity), then subtract total costs.", "starter": "The net profit is calculated by..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £3 million</strong></p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:4c28f093', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which would be variable costs for a building firm? [1 mark]", "options": ["A — Administrative and legal expenses", "B — Bricks and roof tiles", "C — Business rates and buildings insurance", "D — Cement mixers and tools"], "hint": "Variable costs change with the level of output — think about what is used directly in building.", "starter": "Variable costs for a building firm would be..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Bricks and roof tiles</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Bricks and roof tiles are used directly in production and increase as more buildings are constructed. Admin/legal expenses, business rates, insurance, and equipment like cement mixers are either fixed or indirect costs.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:8b9d0010', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q3", "question": "This means that: [1 mark]", "options": ["A — every £100 of sales earns £1.30 less net profit than it used to", "B — for every £100 of sales the company only earns £1.30", "C — net profit levels have fallen by 1.3%", "D — the company has made a net loss of 1.3%"], "caseStudy": "A company has recently experienced a fall in its net profit margin from 4.2% to 2.9%.", "hint": "A profit margin is expressed as pence per £1 of sales. Calculate the difference between the two margins and think about what that means per £100.", "starter": "The fall in net profit margin means that..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — every £100 of sales earns £1.30 less net profit than it used to</strong></p></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered question in the whole paper. If the margin falls from 4.2% to 2.9%, that is a fall of 1.3 pence per pound, so £1.30 for each £100.</p><ul><li>Answer C was the most common wrong answer — a fall from 4.2% to 2.9% is actually a decrease of 31%, not 1.3%</li><li>Answer D was also popular — but the margin remains positive, so a profit is still being made</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:ff86fcde', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q4", "question": "The percentage change in the company''s total costs from 2020 to 2023 was: [1 mark]", "options": ["A — 33%", "B — 37.5%", "C — 50%", "D — 60%"], "caseStudy": "The table below shows a company''s total costs over the last four years.\n\n2020: Operating £200,000 + Other £40,000 = £240,000\n2021: Operating £170,000 + Other £30,000 = £200,000\n2022: Operating £280,000 + Other £30,000 = £310,000\n2023: Operating £320,000 + Other £40,000 = £360,000", "hint": "Add both cost rows together for each year. Then apply the percentage change formula: (new − old) ÷ old × 100.", "starter": "The percentage change in total costs is calculated by..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2020 total: £200,000 + £40,000 = £240,000</li><li>2023 total: £320,000 + £40,000 = £360,000</li><li>Change: £120,000 ÷ £240,000 × 100 = 50%</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:21e2d70e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q5", "question": "The market trader''s gross profit margin was approximately: [1 mark]", "options": ["A — 37%", "B — 63%", "C — 79%", "D — 172%"], "caseStudy": "A market trader paid £4600 for goods which they sold for £12,500.", "hint": "Gross profit = Revenue − Cost of sales. Then: Gross Profit ÷ Revenue × 100.", "starter": "The gross profit margin is calculated by first finding gross profit, which is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 63%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = £12,500 − £4,600 = £7,900</li><li>GPM = £7,900 ÷ £12,500 × 100 = 63.2%</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The correct answer of B was chosen by less than 40% of candidates.</p><ul><li>Many chose A because they did not first calculate gross profit</li><li>Some who did calculate gross profit then chose D because they divided by cost of sales rather than revenue</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:1b86b277', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Over the first three years of trading, the entrepreneur should expect to make: [1 mark]", "options": ["A — average profits of £45,000 per year", "B — average profits of £135,000 per year", "C — profits totalling £15,000", "D — profits totalling £45,000"], "caseStudy": "An entrepreneur has invested £150,000 to start up their own business. Their expected average rate of return is 10% per annum for the first three years.", "hint": "10% per annum means 10% per year. Calculate annual profit first, then multiply by 3.", "starter": "A 10% ARR on a £150,000 investment means..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — profits totalling £45,000</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Annual profit = 10% × £150,000 = £15,000</li><li>Total profit over 3 years = £15,000 × 3 = £45,000</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Only half of candidates identified the correct answer as D.</p><ul><li>Answer A was the most popular wrong answer — candidates confused £15,000/year with £45,000/year</li><li>Answer C was also chosen — candidates calculated annual profit correctly but forgot to multiply by 3</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:3aeae4a6', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Which of the following would be fixed costs of a fruit farm? [1 mark]", "options": ["A — Farm workers'' wages", "B — Plant food and fertiliser", "C — Rent and rates", "D — Seeds and seedlings"], "hint": "Fixed costs do not change with the level of output. Which of these stays the same whether or not crops are being grown?", "starter": "A fixed cost for a fruit farm would be..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Rent and rates</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Rent and rates must be paid regardless of output levels. Workers'' wages, fertiliser and seeds are all variable because they increase when more crops are produced.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:fc9af4e5', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The entrepreneur''s average rate of return is: [1 mark]", "options": ["A — 6.6%", "B — 26.5%", "C — 73.5%", "D — 106%"], "caseStudy": "Four years ago an entrepreneur invested £200,000 to start up their own business. The business is making an average profit of £53,000 per year.", "hint": "ARR = (Average annual profit ÷ Cost of investment) × 100.", "starter": "The average rate of return is calculated by dividing average annual profit by the initial investment..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 26.5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>ARR = £53,000 ÷ £200,000 × 100 = 26.5%</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:9a8f387a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following would help Emma and Henry deal with this problem? [1 mark]", "options": ["A — Holding larger stocks of raw materials", "B — Increasing the labourers'' wages", "C — Issuing shares", "D — Taking on a new partner"], "caseStudy": "Emma and Henry are in a partnership that runs a small building firm. Despite being profitable, the business is having difficulty paying all its expenses.", "hint": "The problem is a cash flow issue, not a profit issue. Which option brings in new capital to fund day-to-day expenses?", "starter": "To deal with the difficulty of paying expenses, Emma and Henry should..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Taking on a new partner</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>A new partner would inject capital into the business, helping to resolve the cash flow problem. Holding more stock or increasing wages would make things worse. Issuing shares is not available to partnerships.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:db20b658', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Pilti plc''s gross profit in 2022 was: [1 mark]", "options": ["A — £18 million", "B — £26 million", "C — £32 million", "D — £58 million"], "caseStudy": "Financial data for Pilti plc in 2022:\n• Revenue: £44 million\n• Expenses: £12 million\n• Net profit: £14 million", "hint": "Rearrange: Gross profit = Net profit + Expenses. Net profit = Gross profit − Expenses.", "starter": "Gross profit is found by adding net profit and expenses together..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — £26 million</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = Net profit + Expenses = £14m + £12m = £26m</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Less than one in five candidates selected the correct answer. Answer C was the most popular wrong answer — candidates confused expenses with cost of sales. The formula rearranges to: Gross profit = Net profit + Expenses.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:24acbfa2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q13", "question": "The lowest cost that Riley can obtain 1,200 litres of cleaning fluid from one supplier is: [1 mark]", "options": ["A — £480", "B — £600", "C — £700", "D — £800"], "caseStudy": "Riley runs his own cleaning business and wishes to keep supply costs as low as possible.\n\nSupplier 1: 100 litre barrels @ £80\nSupplier 2: 200 litre barrels @ £100\nSupplier 3: 1,000 litre barrels @ £600\nSupplier 4: 2,000 litre barrels @ £800", "hint": "Work out how many barrels of each size you would need to get at least 1,200 litres. Then calculate the total cost for each option.", "starter": "To obtain 1,200 litres from one supplier, Riley would need..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — £600</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Supplier 3: 1 × 1,000L barrel = £600, but only 1,000L — not enough</li><li>Riley needs to buy 2 × 1,000L barrels from Supplier 3 = £1,200 — too expensive</li><li>Supplier 3: 1 barrel = 1,000L, need at least 1,200L → buy 2 = £1,200</li><li>Best option: 6 × 200L barrels from Supplier 2 = 1,200L @ £100 each = £600</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Around half of candidates answered correctly. Answer A was most common wrong answer — it is not possible to get 1,200L for £480 from any supplier.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:be4dee0d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which of the following must be true for this business? [1 mark]", "options": ["A — Expenses have fallen by 50%", "B — Net profit has increased by 3%", "C — Profitability has increased by 50%", "D — Revenue has increased by 3%"], "caseStudy": "The net profit margin of a business has increased from 6% in 2021 to 9% in 2022.", "hint": "The question is about the margin (a ratio), not the absolute profit figure. Calculate the percentage change in the margin itself.", "starter": "If the net profit margin has increased from 6% to 9%, this means profitability has changed by..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Profitability has increased by 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = 9% − 6% = 3 percentage points</li><li>% change in profitability = 3 ÷ 6 × 100 = 50%</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered multiple-choice question. The most common wrong answer was B — candidates confused ''net profit'' with ''net profit margin''.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:5f0dd896', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q15", "question": "This data is useful to Amir when making this pricing decision because it shows that: [1 mark]", "options": ["A — changing the price charged for each loaf will have little effect on total revenue", "B — charging a relatively high price for each loaf is likely to increase total revenue", "C — reducing the price charged for each loaf is likely to increase total revenue", "D — the current price should not be changed because it maximises total revenue"], "caseStudy": "Amir runs a market stall that sells bread. His most popular product, the Farmhouse Loaf, is currently priced at £2.00.\n\nExpected weekly sales at various prices:\n£1.50 → 350 loaves\n£1.75 → 250 loaves\n£2.00 → 150 loaves\n£2.25 → 50 loaves", "hint": "Calculate total revenue (price × quantity) for each price point and compare.", "starter": "The data shows that reducing the price is likely to increase total revenue because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — reducing the price charged for each loaf is likely to increase total revenue</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£1.50 × 350 = £525</li><li>£1.75 × 250 = £437.50</li><li>£2.00 × 150 = £300</li><li>£2.25 × 50 = £112.50</li><li>Total revenue is highest at £1.50, so reducing price increases revenue</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:2bbd9cc8', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Pallin Ltd''s average level of profit over the last five years is: [1 mark]", "options": ["A — £4,000 per year", "B — £5,000 per year", "C — £6,400 per year", "D — £8,000 per year"], "caseStudy": "Performance data for Pallin Ltd for the last five years of trading:\n2017: £15,000\n2018: £0\n2019: −£9,000\n2020: £17,000\n2021: −£3,000", "hint": "Add all five profit/loss figures together (remember losses are negative) then divide by 5.", "starter": "The average profit is calculated by adding all five years together and dividing by 5..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £4,000 per year</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£15,000 + £0 + (−£9,000) + £17,000 + (−£3,000) = £20,000</li><li>£20,000 ÷ 5 = <strong>£4,000 per year</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:0ec610bf', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q21", "question": "This means: [1 mark]", "options": ["A — for every £10 of sales, it makes £5 profit after all costs have been paid", "B — the perfume shop''s variable costs are exactly half of its fixed costs", "C — the shop charges customers double what it pays when buying the perfume", "D — to make £10 of profit, it needs to sell £50 of perfume"], "caseStudy": "A perfume shop has a gross profit margin of 50%.", "hint": "GPM = (Gross Profit ÷ Revenue) × 100. If GPM is 50%, what is the relationship between the buying price and the selling price?", "starter": "A gross profit margin of 50% means that..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — the shop charges customers double what it pays when buying the perfume</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>If GPM = 50%, then gross profit = 50% of revenue. This means cost of sales = 50% of revenue. If cost = 50% of selling price, then selling price = 2 × cost — i.e. the shop charges double what it paid.</p></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered question in Section A. Answer A was most common wrong answer — £5 is 50% of £10, but this profit is after variable costs only, not ''all costs''.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:4b8efe2d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q22", "question": "The manufacturer''s estimated total cost for the year is: [1 mark]", "options": ["A — £66,840", "B — £77,500", "C — £85,900", "D — £86,800"], "caseStudy": "A drum kit manufacturer plans to make 500 drum kits this year. Estimated costs:\n• Raw materials: £40 per drum kit\n• Rent: £600 per month\n• Heating and lighting: £900 per quarter\n• Other expenses: £56,000 per annum", "hint": "Convert all costs to annual figures first, then add them together. Remember: rent × 12, heating × 4.", "starter": "To calculate total annual costs, I need to convert all costs to annual figures..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £86,800</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Variable: 500 × £40 = £20,000</li><li>Rent: £600 × 12 = £7,200</li><li>Heating & lighting: £900 × 4 = £3,600</li><li>Other expenses: £56,000</li><li>Total = £20,000 + £7,200 + £3,600 + £56,000 = <strong>£86,800</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:354ca3f5', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q23", "question": "Which of the following would be a variable cost for a restaurant? [1 mark]", "options": ["A — Advertising fees", "B — Buildings insurance", "C — Chef''s salary", "D — Fruit and vegetables"], "hint": "Variable costs increase as output increases. Which item would a restaurant need more of when serving more meals?", "starter": "A variable cost for a restaurant would be..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Fruit and vegetables</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Fruit and vegetables are ingredients used directly in food preparation — the more meals served, the more ingredients needed. Salaries, insurance and advertising fees are fixed or semi-fixed costs.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:3e60f4b8', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Tictal Ltd''s gross profit margin in 2020 was: [1 mark]", "options": ["A — 25%", "B — 45%", "C — 55%", "D — 75%"], "caseStudy": "Financial data for Tictal Ltd in 2020:\n• Revenue: £180,000\n• Cost of sales: £45,000\n• Expenses: £36,000", "hint": "Gross profit = Revenue − Cost of sales. Then GPM = (Gross profit ÷ Revenue) × 100. Do not use expenses for this calculation.", "starter": "Gross profit margin is calculated using revenue and cost of sales only..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — 75%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = £180,000 − £45,000 = £135,000</li><li>GPM = £135,000 ÷ £180,000 × 100 = <strong>75%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:e60bc429', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q25", "question": "Assuming the forecasted figures are correct, the average rate of return for this upgrade will be: [1 mark]", "options": ["A — 33%", "B — 50%", "C — 67%", "D — 100%"], "caseStudy": "An advertising agency wishes to upgrade its design software at a cost of £60,000. The net cash flow generated by the software for each of the next two years is forecast to be £60,000.", "hint": "Total profit = total income − cost of investment. Then ARR = (average annual profit ÷ cost) × 100.", "starter": "The ARR is calculated by first finding total profit (total income minus the cost)..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £60,000 × 2 = £120,000</li><li>Total profit = £120,000 − £60,000 = £60,000</li><li>Average annual profit = £60,000 ÷ 2 = £30,000</li><li>ARR = £30,000 ÷ £60,000 × 100 = <strong>50%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:c54020b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q27", "question": "What percentage reduction in transport costs has Shanco plc achieved? [1 mark]", "options": ["A — 6%", "B — 7%", "C — 14.3%", "D — 16.7%"], "caseStudy": "Shanco plc has managed to reduce its transport costs from £0.7 million in 2019 to £0.6 million in 2020.", "hint": "Percentage change = (change ÷ original) × 100. The original is the 2019 figure.", "starter": "The percentage reduction is calculated using the 2019 figure as the original..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 14.3%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £0.7m − £0.6m = £0.1m</li><li>% reduction = £0.1m ÷ £0.7m × 100 = <strong>14.3%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:5467638c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q29", "question": "The company''s labour costs in 2019 were: [1 mark]", "options": ["A — £3.6 million", "B — £5.4 million", "C — £12.6 million", "D — £14.4 million"], "caseStudy": "A company''s total costs in 2019 were £9 million. The company''s labour costs were 40% of the company''s total costs.", "hint": "Calculate 40% of £9 million.", "starter": "Labour costs = 40% × £9 million = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £3.6 million</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£9m × 0.40 = <strong>£3.6 million</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:175e2e65', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q30", "question": "Variable costs: [1 mark]", "options": ["A — are not affected by changes in output", "B — fall as output rises", "C — increase as output rises", "D — remain constant over time"], "hint": "Think about what happens to variable costs when a business produces more — e.g. more raw materials needed.", "starter": "Variable costs increase as output rises because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — increase as output rises</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Variable costs (e.g. raw materials, direct labour) rise directly in line with the level of production. Fixed costs remain constant; variable costs do not.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:1ae8eeb8', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q31", "question": "The expected average rate of return for this purchase is: [1 mark]", "options": ["A — £1,000", "B — £3,000", "C — 16.67%", "D — 33.33%"], "caseStudy": "A furniture maker intends to purchase a new wood cutting machine:\n• Cost of machine: £6,000\n• Income Year 1: £3,000\n• Income Year 2: £3,000\n• Income Year 3: £3,000", "hint": "Total profit = total income − cost. Average annual profit = total profit ÷ years. ARR = (average annual profit ÷ cost) × 100.", "starter": "The ARR is calculated by first working out total profit over the machine''s life..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 16.67%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £3,000 × 3 = £9,000</li><li>Total profit = £9,000 − £6,000 = £3,000</li><li>Average annual profit = £3,000 ÷ 3 = £1,000</li><li>ARR = £1,000 ÷ £6,000 × 100 = <strong>16.67%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:b5c6810f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q33", "question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be: [1 mark]", "options": ["A — £1,075 per year", "B — £4,750 per year", "C — £12,075 per year", "D — £15,750 per year"], "caseStudy": "Andrea specialises in painting portraits. She estimates that:\n• Variable costs for labour: £52 per portrait\n• Variable costs for materials: £23 per portrait\n• Fixed costs: £1,000 per month", "hint": "Total variable cost = (£52 + £23) × 50. Total fixed cost = £1,000 × 12. Add them together.", "starter": "Total costs = total variable costs + total fixed costs = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £15,750 per year</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Variable cost per portrait = £52 + £23 = £75</li><li>Total variable costs = £75 × 50 = £3,750</li><li>Total fixed costs = £1,000 × 12 = £12,000</li><li>Total costs = £3,750 + £12,000 = <strong>£15,750</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:bd129f1c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q34", "question": "This data is useful to Seiji when making business decisions because it shows that: [1 mark]", "options": ["A — labour costs are increasing every year", "B — profit levels are falling", "C — the business is producing less than it used to", "D — total costs are increasing"], "caseStudy": "Seiji, a sole trader, has produced a table showing the costs of running his business over the last four years.\n\n2015: Labour £44,000 | Raw materials £36,000 | Other £18,000\n2016: Labour £66,000 | Raw materials £35,000 | Other £25,000\n2017: Labour £65,000 | Raw materials £34,000 | Other £32,000\n2018: Labour £62,000 | Raw materials £33,000 | Other £39,000", "hint": "Add up all three cost rows for each year and compare. What trend can you see?", "starter": "The data shows that total costs are..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — total costs are increasing</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2015: £44,000 + £36,000 + £18,000 = £98,000</li><li>2016: £66,000 + £35,000 + £25,000 = £126,000</li><li>2017: £65,000 + £34,000 + £32,000 = £131,000</li><li>2018: £62,000 + £33,000 + £39,000 = £134,000</li><li>Labour costs fell after 2016, so A is wrong. No revenue data, so B and C cannot be confirmed. D is correct.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:182cd390', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q35", "question": "Assuming the forecasted figures are correct, the average rate of return for upgrading the robotics will be: [1 mark]", "options": ["A — 5%", "B — 20%", "C — 25%", "D — 125%"], "caseStudy": "A tractor manufacturer wishes to upgrade its robotics at a total cost of £4 million. The cash inflow for each of the next five years is forecasted to be £1 million.", "hint": "Total profit = total income − cost. Average annual profit = total profit ÷ years. ARR = (average annual profit ÷ cost) × 100.", "starter": "Total income = £1m × 5 = £5m. Total profit = £5m − £4m = £1m..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £1m × 5 = £5m</li><li>Total profit = £5m − £4m = £1m</li><li>Average annual profit = £1m ÷ 5 = £200,000</li><li>ARR = £200,000 ÷ £4,000,000 × 100 = <strong>5%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:1df18a21', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q36", "question": "The agency''s percentage increase in spending on digital communications from 2017 to 2018 was approximately equal to: [1 mark]", "options": ["A — 48%", "B — 52%", "C — 110%", "D — 210%"], "caseStudy": "A market research agency spent £250,000 on digital communication in 2017 and £525,000 in 2018.", "hint": "The spending has more than doubled, so the answer must be more than 100%. Use the 2017 figure as the original.", "starter": "Percentage change = (change ÷ original) × 100 = (£275,000 ÷ £250,000) × 100 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 110%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £525,000 − £250,000 = £275,000</li><li>% change = £275,000 ÷ £250,000 × 100 = <strong>110%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This had the greatest proportion of incorrect answers of all the MCQ questions. The figures have more than doubled, so the answer must be greater than 100%. A common misconception is dividing by the new value instead of the original.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:9f050750', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q38", "question": "What was the market stall''s revenue? [1 mark]", "options": ["A — £200", "B — £1,000", "C — £1,200", "D — £2,200"], "caseStudy": "A market stall sells bread for £1 a loaf and cookies for 60p each. Yesterday 1,000 loaves of bread and 2,000 cookies were sold.", "hint": "Revenue = price × quantity for each product. Then add the two totals together.", "starter": "Total revenue = (bread revenue) + (cookie revenue) = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £2,200</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Bread revenue = £1 × 1,000 = £1,000</li><li>Cookie revenue = £0.60 × 2,000 = £1,200</li><li>Total revenue = £1,000 + £1,200 = <strong>£2,200</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:cb3c0ecf', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q39", "question": "Gross profit margin is: [1 mark]", "options": ["A — a computerised method of production", "B — a financial ratio", "C — a pricing method", "D — a variable cost"], "hint": "Think about what category gross profit margin belongs to — it''s a way of measuring financial performance.", "starter": "Gross profit margin is classified as..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — a financial ratio</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Gross profit margin expresses gross profit as a proportion (ratio) of revenue. It is used to assess a business''s financial performance — it is not a method of production, pricing strategy, or cost.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:f27b4b6f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q40", "question": "Which one of the following must be true for this business? [1 mark]", "options": ["A — The business cannot pay its short term debts", "B — The business has made a loss", "C — The business has revenues that are greater than its costs", "D — The business is operating below its break even level"], "caseStudy": "A business has a net profit margin of 8%.", "hint": "A positive net profit margin means the business is profitable. What does that tell you about revenues vs costs?", "starter": "A net profit margin of 8% means that..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The business has revenues that are greater than its costs</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>A positive net profit margin of 8% means the business is making a profit — so revenues must exceed total costs. It does not tell us about short-term debt or whether it is above break-even in terms of units.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:660a7f00', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q41", "question": "What is the approximate increase between 2015 and 2016 in Jimco plc''s production costs? [1 mark]", "options": ["A — 0.9%", "B — 1.6%", "C — 7.0%", "D — 7.5%"], "caseStudy": "The production costs for Jimco plc were £21.3 million in 2015 and £22.9 million in 2016.", "hint": "Percentage change = (change ÷ original) × 100. Use the 2015 figure as the original.", "starter": "Percentage increase = (£1.6m ÷ £21.3m) × 100 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — 7.5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £22.9m − £21.3m = £1.6m</li><li>% change = £1.6m ÷ £21.3m × 100 = <strong>7.5%</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:e7104661', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q43", "question": "In 2018 Pluck and Grow Ltd made: [1 mark]", "options": ["A — a loss of £52,000", "B — a loss of £42,000", "C — a profit of £16,000", "D — a profit of £26,000"], "caseStudy": "Financial data for Pluck and Grow Ltd in 2018:\n• Total revenue: £68,000\n• Total labour costs: £26,000\n• Total material costs: £16,000\n• Other costs: £10,000", "hint": "Add up all costs, then subtract from revenue.", "starter": "Total costs = £26,000 + £16,000 + £10,000 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — a profit of £16,000</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total costs = £26,000 + £16,000 + £10,000 = £52,000</li><li>Profit = £68,000 − £52,000 = <strong>£16,000</strong></li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:ed12fcd3', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q44", "question": "The data shows that: [1 mark]", "options": ["A — the company prefers to transport its goods by air", "B — the company''s transport costs have fallen year on year", "C — GLU plc spent more than £1.25 million on transport costs in 2018", "D — GLU plc transports more goods by rail than by road"], "caseStudy": "Transport costs of Global Logistics United plc (GLU plc) for the last five years:\n\nBy road: 2014 £150k | 2015 £160k | 2016 £170k | 2017 £180k | 2018 £190k\nBy rail: 2014 £350k | 2015 £370k | 2016 £390k | 2017 £410k | 2018 £430k\nBy air: 2014 £600k | 2015 £620k | 2016 £635k | 2017 £640k | 2018 £650k", "hint": "Add up all three transport modes for 2018 and compare to £1.25 million.", "starter": "Total transport costs in 2018 = £190k + £430k + £650k = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — GLU plc spent more than £1.25 million on transport costs in 2018</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2018 total: £190,000 + £430,000 + £650,000 = £1,270,000 > £1.25m ✓</li><li>Costs are rising (not falling), so B is wrong</li><li>Higher spending on air does not mean preference, so A is unconfirmed</li><li>Higher costs by rail doesn''t confirm more goods transported, so D is unconfirmed</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:exam:4abfeab8', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'exam', 'mcq', 1, '{"num": "Q45", "question": "What was Exobike''s gross profit margin? [1 mark]", "options": ["A — 68%", "B — 147%", "C — £4,704", "D — £14,700"], "caseStudy": "Exobike made a gross profit of £9,996 from selling 42 exercise bikes at £350 each.", "hint": "First calculate total revenue (price × quantity). Then GPM = (gross profit ÷ revenue) × 100. Note: two options are not even percentages, so you can eliminate them.", "starter": "Total revenue = 42 × £350 = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 68%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Revenue = 42 × £350 = £14,700</li><li>GPM = £9,996 ÷ £14,700 × 100 = <strong>68%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Candidates could eliminate C and D immediately as they are monetary values, not percentages. Even without doing the full calculation, knowledge that a GPM is a percentage narrows the answer to A or B — and 68% is a realistic margin while 147% is not possible.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-2-organisational-structures:mcq:f826bf1e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A business with a tall organisational structure will have:", "options": ["A high market share", "Lots of distribution channels", "Multiple layers of authority", "Short chains of command"]}'::jsonb, '{"answer": 2, "explain": "A tall structure is defined by having many layers of authority from top to bottom. This creates long chains of command — not short ones. Market share and distribution channels are unrelated to structure."}'::jsonb),
('business:3-2-organisational-structures:mcq:11f9dd3a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A clothing designer may choose to flatten its organisational structure to reduce the:", "options": ["Creativity of its garment designers", "Independence of its fabric buyers", "Need for innovation and change", "Time it takes to respond to changes in fashion"]}'::jsonb, '{"answer": 3, "explain": "A flat structure has fewer layers, so communication is faster. This means the business can respond more quickly to changes in fashion trends. Flattening does NOT reduce creativity — it usually enhances it."}'::jsonb),
('business:3-2-organisational-structures:mcq:a6f284d1', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "The span of control of the Production Manager (who has 3 Production Supervisors reporting directly to them) is:", "options": ["1", "3", "21", "63"]}'::jsonb, '{"answer": 1, "explain": "The span of control is the number of people who report DIRECTLY to a manager. Only the 3 Production Supervisors report directly to the Production Manager — not the 20 workers under each supervisor."}'::jsonb),
('business:3-2-organisational-structures:mcq:f3b60fe4', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A business may choose to have a flat organisational structure because it:", "options": ["Gives employees more opportunities for promotion", "Lengthens the organisation''s chain of command", "Reduces the likelihood of mistakes in vertical communication", "Slows down the organisation''s response to changes in the market"]}'::jsonb, '{"answer": 2, "explain": "Fewer layers means fewer people for a message to pass through — so there are fewer opportunities for it to be changed or distorted. This reduces mistakes in vertical (upward/downward) communication."}'::jsonb),
('business:3-2-organisational-structures:mcq:7b8a064f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "A flat organisational structure has:", "options": ["A long chain of command", "Few levels of authority", "Narrow spans of control", "No specific person in overall charge"]}'::jsonb, '{"answer": 1, "explain": "A flat structure is defined by having FEW levels (layers) of authority — perhaps only 2 or 3. It has WIDE (not narrow) spans of control and SHORTER (not longer) chains of command."}'::jsonb),
('business:3-2-organisational-structures:mcq:2134ac05', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Who is a director''s subordinate?", "options": ["A customer", "A manager", "A shareholder", "A supplier"]}'::jsonb, '{"answer": 1, "explain": "Subordinates are the workers that a line manager (or director) is responsible for and has authority over. Managers report to directors, making them subordinates. Customers, shareholders and suppliers are external parties."}'::jsonb),
('business:3-2-organisational-structures:mcq:16ae2db6', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage to a fruit farm of employing temporary workers to pick the fruit?", "options": ["Discrimination laws do not apply because the work is only for a few weeks", "Induction training will not be required because the work is not permanent", "The number of workers employed can be varied according to the season", "Workers are likely to be more committed to their jobs and pick more fruit"]}'::jsonb, '{"answer": 2, "explain": "The key advantage of temporary workers is flexibility — the farm can increase or decrease the number of workers to match seasonal demand for fruit picking. Discrimination laws ALWAYS apply, and induction training is still needed."}'::jsonb),
('business:3-2-organisational-structures:mcq:d5ebd61e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "Which one of the following is a benefit to a flower shop of employing extra temporary sales staff on Valentine''s Day?", "options": ["More customers can be served", "Roses can be sold for cheaper prices", "The flowers will be fresher", "Workers can be paid less than the minimum wage"]}'::jsonb, '{"answer": 0, "explain": "With more staff, the shop can serve more customers during the peak demand on Valentine''s Day — reducing queues and improving customer service. Temporary staff cannot be paid below the minimum wage."}'::jsonb),
('business:3-2-organisational-structures:mcq:0ce483b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "The main financial benefit of delayering for Leigh Hire Ltd (removing two supervisor roles at £35,000 each, giving the Service Manager a £10,000 pay rise) is a saving of:", "options": ["£35,000 per year", "£60,000 per year", "£70,000 per year", "£80,000 per year"]}'::jsonb, '{"answer": 1, "explain": "Two roles at £35,000 = £70,000 saved. Less the £10,000 increase to the Service Manager = net saving of £60,000 per year. This is the key financial application figure for the Leigh Hire case study."}'::jsonb),
('business:3-2-organisational-structures:mcq:8e60254d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'mcq', 'mcq', 1, '{"question": "What is the mean average managerial span of control at POD Ltd, which has 5 managers each managing: 6 accounts clerks, 4 clerical assistants, 28 production workers, 5 sales reps, and 3 HR assistants?", "options": ["7.7", "8.5", "9.2", "10.2"]}'::jsonb, '{"answer": 1, "explain": "Total subordinates = 6+4+28+5+3 = 46. Divided by 5 managers = 9.2 per manager. But the Managing Director also manages 5 managers. Mean average across all 6 managers = (46+5)/6 = 8.5."}'::jsonb),
('business:3-2-organisational-structures:tf:d8a1501b', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A tall organisational structure has a wide span of control."}'::jsonb, '{"answer": false, "explain": "Tall structures have a NARROW span of control — each manager supervises fewer people. FLAT structures have a wide span of control."}'::jsonb),
('business:3-2-organisational-structures:tf:747f3f13', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Delayering means adding more layers to an organisational structure."}'::jsonb, '{"answer": false, "explain": "Delayering means REMOVING layers to make the structure flatter. It reduces the number of management levels, usually to save money and speed up communication."}'::jsonb),
('business:3-2-organisational-structures:tf:2a6e9afa', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "The span of control of a manager with 3 supervisors, each managing 20 workers, is 3."}'::jsonb, '{"answer": true, "explain": "Correct. Span of control only counts DIRECT reports. The 3 supervisors report directly to the manager. The 60 workers report to their supervisors — not directly to the manager."}'::jsonb),
('business:3-2-organisational-structures:tf:93ea9b12', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Part-time workers have fewer employment rights than full-time workers."}'::jsonb, '{"answer": false, "explain": "This is a common misconception. Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect their rights."}'::jsonb),
('business:3-2-organisational-structures:tf:9d5c1408', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A flat organisational structure is best suited to large, non-creative businesses."}'::jsonb, '{"answer": false, "explain": "Flat structures suit creative businesses (e.g. game design) and smaller businesses. Large, non-creative businesses with clear tasks tend to suit TALL structures with defined authority."}'::jsonb),
('business:3-2-organisational-structures:tf:a7860172', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Delegation means giving a subordinate responsibility for a task while the manager remains ultimately accountable."}'::jsonb, '{"answer": true, "explain": "Correct. Delegation gives the subordinate authority and responsibility to make certain decisions, but the manager is still ultimately responsible for the outcome."}'::jsonb),
('business:3-2-organisational-structures:tf:aa47718f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Working from home always increases worker productivity."}'::jsonb, '{"answer": false, "explain": "It CAN increase productivity (less commute stress, flexible hours) but NOT always. Distractions at home (children, TV) and social isolation can reduce productivity. The effect varies by individual and role."}'::jsonb),
('business:3-2-organisational-structures:tf:1fe931b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Leigh Hire Ltd''s delayering plan would save £70,000 in wages per year."}'::jsonb, '{"answer": false, "explain": "The saving is £60,000. Two roles at £35,000 each = £70,000 saved. MINUS the £10,000 pay rise for the Service Manager = net saving of £60,000 per year."}'::jsonb),
('business:3-2-organisational-structures:tf:432ba1b2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A zero-hours worker is not guaranteed any work hours each week."}'::jsonb, '{"answer": true, "explain": "Correct. Zero-hours contracts mean the worker has a contract but is not guaranteed any hours. They are called in when needed, sometimes at very short notice."}'::jsonb),
('business:3-2-organisational-structures:tf:f4ab7a5a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Autocratic leaders tend to prefer flat organisational structures."}'::jsonb, '{"answer": false, "explain": "Autocratic leaders prefer TALL structures because they give more control — narrow spans of control mean managers have fewer people to supervise, and the long chain of command keeps authority centralised at the top."}'::jsonb),
('business:3-2-organisational-structures:tf:a51682ec', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Hybrid working means working entirely from home, with no time in the office."}'::jsonb, '{"answer": false, "explain": "Hybrid working means working PART of the time at home AND part in the office — not entirely from home. Working entirely from home is simply ''working from home''."}'::jsonb),
('business:3-2-organisational-structures:tf:6c50cdeb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "A self-employed person receives holiday pay from a client business."}'::jsonb, '{"answer": false, "explain": "Self-employed workers are NOT employees. They do not receive holiday pay, sick pay or employer pension contributions from the businesses they work for. This is one of the key disadvantages of self-employment."}'::jsonb),
('business:3-2-organisational-structures:tf:580c0d8a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "JD Wetherspoon uses flexible contracts with shifts varying from 4 to 10 hours based on demand."}'::jsonb, '{"answer": true, "explain": "Correct. JD Wetherspoon uses flexible-working contracts where shifts vary between 4 and 10 hours to match demand — more staff during busy lunch and evening periods, fewer during quiet mornings."}'::jsonb),
('business:3-2-organisational-structures:tf:44b95794', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tf', 'tf', 1, '{"question": "Beautiful Buds plc would make a net annual saving of £1 million from its delayering plan, after removing Middle Managers and Team Leaders and adding supervisors."}'::jsonb, '{"answer": true, "explain": "Correct. £600k (Middle Managers) + £700k (Team Leaders) = £1.3m saved. Less £300k (10 new supervisors) = £1m net annual saving. The £200k redundancy is a one-off cost."}'::jsonb),
('business:3-2-organisational-structures:learn:537a7f35', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Core Terminology", "reading": "<ul>\n<li><strong>Organisational structure</strong> — how people and departments are arranged within a business; the hierarchy of employees</li>\n<li><strong>Organisation chart</strong> — a diagram showing how workers are organised and who is in charge of whom</li>\n<li><strong>Layers</strong> — the number of levels of authority in a chain of command</li>\n<li><strong>Authority</strong> — the power to make decisions and tell other workers what to do</li>\n<li><strong>Line manager</strong> — the person directly in charge of other workers; the person a worker is responsible to</li>\n<li><strong>Subordinates</strong> — workers that a line manager is responsible for</li>\n<li><strong>Chain of command</strong> — the path of authority along which instructions pass, from the CEO downwards</li>\n<li><strong>Span of control</strong> — the number of employees/subordinates that report directly to a manager</li>\n<li><strong>Delegation</strong> — when a manager gives a subordinate authority and responsibility to make certain decisions (the manager remains ultimately responsible)</li>\n<li><strong>Accountability</strong> — the responsibility a person has for a job; they take blame for what goes wrong as well as credit for what goes well</li>\n<li><strong>Delayering</strong> — when a business reduces the number of layers in its structure, making it flatter</li>\n<li>\n     <a href=\"extra/org_chartV2.html\" target=\"_blank\" rel=\"noopener noreferrer\"> Our School Organisation chart </a> </li>\n</ul>", "question": "When a manager delegates a task to a subordinate, who remains ultimately responsible for the outcome?", "options": ["The manager who delegated it", "Only the subordinate carrying out the task", "No one — responsibility disappears once delegated", "The subordinate''s line manager''s line manager"]}'::jsonb, '{"answer": 0, "explain": "The glossary states that when a manager delegates, they give authority and responsibility to a subordinate but remain ultimately responsible."}'::jsonb),
('business:3-2-organisational-structures:learn:01d3e297', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Tall vs Flat Organisational Structures", "reading": "<p><strong>Tall structure:</strong> Many layers; narrow span of control. Suited to large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Tall</div>\n<div class=\"pro-item\">Clear lines of communication and authority</div>\n<div class=\"pro-item\">Easier supervision — fewer direct reports per manager</div>\n<div class=\"pro-item\">Workers are clear who they are responsible to</div>\n<div class=\"pro-item\">Promotion opportunities motivate workers</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Tall</div>\n<div class=\"con-item\">Subordinates feel too controlled — can stifle motivation</div>\n<div class=\"con-item\">Slower communications — many layers to pass through</div>\n<div class=\"con-item\">Messages more likely to be distorted through many people</div>\n<div class=\"con-item\">Workers may only talk to immediate colleagues</div>\n</div>\n</div>\n<p style=\"margin-top:12px;\"><strong>Flat structure:</strong> Few layers (2–3); wide span of control. Suited to creative businesses (e.g. game design) and smaller businesses where workers feeling valued matters.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Flat</div>\n<div class=\"pro-item\">Workers feel trusted — managers must delegate widely</div>\n<div class=\"pro-item\">Easier to share ideas — more likely to know bosses directly</div>\n<div class=\"pro-item\">Faster communication — fewer layers</div>\n<div class=\"pro-item\">Messages less likely to be changed or distorted</div>\n<div class=\"pro-item\">Saves money — fewer layers of managers needed</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Flat</div>\n<div class=\"con-item\">Lines of communication not always clear</div>\n<div class=\"con-item\">Few promotion opportunities — can reduce motivation</div>\n<div class=\"con-item\">Managers may have too many people to look after</div>\n</div>\n</div>", "question": "According to the notes, which type of business is a tall structure best suited to?", "options": ["Small creative businesses like game design studios that value flexibility", "Large organisations that have very clear limited tasks", "Businesses that want the fastest possible communication", "Businesses wanting to save money on management wages"]}'::jsonb, '{"answer": 1, "explain": "The notes state tall structures suit large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies)."}'::jsonb),
('business:3-2-organisational-structures:learn:e816d0b4', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Choose Different Structures", "reading": "<p>The structure adopted depends on several factors:</p>\n<ul>\n<li><strong>Scale of business</strong> — large businesses usually require hierarchical structures for clear control; small businesses find this less important</li>\n<li><strong>Function</strong> — organised by functional areas (Marketing, Finance, Production, HR)</li>\n<li><strong>Product</strong> — organised by different product lines</li>\n<li><strong>Place</strong> — organised by locations (e.g. regional offices)</li>\n<li><strong>Nature of the business</strong> — creative businesses suit flat structures; clear-task businesses may suit tall</li>\n<li><strong>Type of leadership</strong> — autocratic leaders prefer tall structures to maintain control</li>\n<li><strong>Effective communication</strong> — whichever structure results in the best communication for that specific organisation</li>\n</ul>\n<p><strong>Delayering:</strong> Businesses reduce layers to save money and gain the advantages of flat structures — faster communication, more delegated authority. e.g. Leigh Hire Ltd saved £60,000 per year by removing two supervisor roles.</p>", "question": "What does ''delayering'' mean in the context of organisational structure?", "options": ["Increasing the number of management layers for better control", "Changing from a product-based to a place-based structure", "Reducing the number of layers in a structure to make it flatter", "Replacing autocratic leaders with democratic ones"]}'::jsonb, '{"answer": 2, "explain": "The card defines delayering as businesses reducing layers to save money and gain flat-structure advantages, citing Leigh Hire Ltd saving £60,000/year."}'::jsonb),
('business:3-2-organisational-structures:learn:3c4c58b7', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Full-time, Part-time & Temporary Working", "reading": "<p><strong>Full-time:</strong> 35+ hours per week. Worker permanently available; business pays even when no work is being done.</p>\n<p><strong>Part-time:</strong> Under 35 hours per week. Part-time employees have the SAME employment rights as full-time workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Part-time — Business</div>\n<div class=\"pro-item\">Can use workers at peak times; saves overtime; more recruitment choice</div>\n<div class=\"con-item\">Higher training costs per head; more supervision time needed</div>\n</div>\n<div>\n<div class=\"col-head\">Part-time — Worker</div>\n<div class=\"pro-item\">Can work when it suits (school hours, students, semi-retired)</div>\n<div class=\"con-item\">Lower income; uncertainty if hours are variable; inconvenient split shifts</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Temporary working:</strong> Short period/fixed-term contract (e.g. seasonal work in agriculture or Christmas retail). Workers can be used when needed without long-term commitment. Risk: lack of commitment, training costs wasted.</p>\n<p><strong>Zero-hours contract:</strong> A person has a contract but is not guaranteed any hours. Informed when needed, sometimes at short notice.</p>", "question": "What best describes a zero-hours contract?", "options": ["A contract only available to full-time staff", "A contract that removes all employment rights", "A contract for exactly 35 hours per week", "A contract with no guaranteed number of hours"]}'::jsonb, '{"answer": 3, "explain": "The notes define a zero-hours contract as one where a person has a contract but is not guaranteed any hours, being informed when needed."}'::jsonb),
('business:3-2-organisational-structures:learn:65f3718a', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Flexible Working, Home & Hybrid Working", "reading": "<p><strong>Flexible working:</strong> Working partly at the workplace and partly elsewhere, or at variable times. Includes flexi-time (working weekly hours in fewer days) and shift working.</p>\n<p><strong>Working from home:</strong> Completing work in the home. <strong>Hybrid working:</strong> Part of the time at home, part in an office.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Home/Hybrid — Business</div>\n<div class=\"pro-item\">Saves on office space/rent; increased productivity; wider recruitment (don''t need to live locally)</div>\n<div class=\"con-item\">Harder to monitor work; communication can be poor; technology costs</div>\n</div>\n<div>\n<div class=\"col-head\">Home/Hybrid — Worker</div>\n<div class=\"pro-item\">Saves time and money on travel; less stress; can work around family commitments</div>\n<div class=\"con-item\">Distractions at home; social isolation; higher utility bills</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Case study — Wokingham Council:</strong> Introduced flexible/hot-desking working; saved money on office space; productivity improved and absenteeism fell. Success depended on ICT (calls transferred to mobile phones).</p>\n<p><strong>Case study — BP:</strong> Moved 6,000 staff to hybrid model (3 days office, 2 days home) to reduce high London office costs.</p>", "question": "What distinguishes ''hybrid working'' from simply ''working from home''?", "options": ["Hybrid splits time between home and the office itself", "Hybrid working is only available to managers", "Hybrid working means fewer hours are worked overall", "Hybrid working removes the need for any office space"]}'::jsonb, '{"answer": 0, "explain": "The card defines working from home as being completed entirely at home, while hybrid working means part of the time at home and part in an office."}'::jsonb),
('business:3-2-organisational-structures:learn:f15d0c1f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Self-Employment & Mobile Working", "reading": "<p><strong>Self-employment:</strong> When people work in their own business, selling their work to buyers (consumers or other businesses). Examples: plumbers, electricians, taxi drivers. In early 2020, 5.03 million people were self-employed (15.3% of UK working population).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Pros of Self-Employment</div>\n<div class=\"pro-item\">Being your own boss; high motivation</div>\n<div class=\"pro-item\">Can earn more by working harder/faster</div>\n<div class=\"pro-item\">Freedom to choose work and clients</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Cons of Self-Employment</div>\n<div class=\"con-item\">No guaranteed income</div>\n<div class=\"con-item\">No holiday pay, sick pay or employer pension contributions</div>\n<div class=\"con-item\">Loss of employment rights (e.g. unfair dismissal protection)</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Working while mobile:</strong> Working while travelling or on the move. Made easier by technology — email, video calls, cloud software.</p>\n<p><strong>Benefit for business:</strong> EDF used self-employed workers for Hinkley Point C construction — only paid for specialist skills when needed, keeping costs lower and reducing long-term commitments.</p>", "question": "Which of these is a genuine drawback of being self-employed, according to the notes?", "options": ["Being told exactly what work to do by a line manager", "No holiday pay, sick pay or pension contributions", "A guaranteed weekly income regardless of work done", "Automatic protection against unfair dismissal"]}'::jsonb, '{"answer": 1, "explain": "The notes list no holiday pay, sick pay or employer pension contributions as a key con of self-employment, alongside no guaranteed income and loss of rights like unfair dismissal protection."}'::jsonb),
('business:3-2-organisational-structures:learn:01fec437', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'learn', 'mcq', 1, '{"readingTitle": "Case Studies Linked to Concepts", "reading": "<p><strong>Griffin Engineering Ltd:</strong> Functional hierarchy with 5 layers. Illustrates chain of command, span of control (Sales Manager = 5), and delegation (Production Manager → Stock Control Manager).</p>\n<p><strong>J.J. Jewellery:</strong> Small family business, flat structure (3 layers). Myiesha (Shop Manager) has span of control of 5. Mix of 2 full-time and 2 part-time shop assistants.</p>\n<p><strong>Leigh Hire Ltd (delayering):</strong> Removed two supervisor roles (£35k each) and gave work to Service Manager (+£10k). Net saving: £60,000/year. Risk: wider span of control for Service Manager may worsen communication.</p>\n<p><strong>JD Wetherspoon:</strong> 38,000 workers; flexible contracts with shifts varying 4–10 hours based on demand. Currently short of 6,000 staff — suggests flexible/insecure contracts may deter applicants.</p>\n<p><strong>HSBC:</strong> Over 70% of call centre employees now work from home permanently. Benefits: lower overhead costs, productivity gains. Risks: monitoring difficulties, technology costs.</p>\n<p><strong>Beautiful Buds plc (delayering):</strong> Removing Middle Managers (£600k saving) and Team Leaders (£700k saving) saves £1.3m. Adding 10 supervisors costs £300k. Net annual saving: £1m (after £200k one-off redundancy cost).</p>", "question": "In the Griffin Engineering Ltd case study, the Sales Manager''s span of control is 5. What does this figure represent?", "options": ["The total number of employees in the whole business", "The number of layers in the chain of command", "Employees who report directly to the Sales Manager", "The number of years the Sales Manager has worked there"]}'::jsonb, '{"answer": 2, "explain": "The card uses Griffin Engineering to illustrate span of control as the number of direct reports to a manager, here the Sales Manager''s span of 5."}'::jsonb),
('business:3-2-organisational-structures:misc:f484cd40', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The organisational structure and the organisation chart are the same thing.</p><p><strong>✅ The correct idea:</strong> They are different. The STRUCTURE is the actual hierarchy — how people and authority are arranged. The CHART is the DIAGRAM that shows that structure visually. You can have a structure without a chart, but a chart represents the structure.</p>", "question": "What is the correct relationship between an organisational structure and an organisation chart?", "options": ["They are two words for exactly the same thing", "The chart is the actual hierarchy, and the structure is only the diagram", "A business can have a chart but never a structure", "The chart is a diagram representing the structure"]}'::jsonb, '{"answer": 3, "explain": "The card clarifies the structure is the actual hierarchy while the chart is the diagram that represents it visually — they are not identical."}'::jsonb),
('business:3-2-organisational-structures:misc:91353b5c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Part-time workers have fewer employment rights than full-time workers.</p><p><strong>✅ The correct idea:</strong> Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect the type or permanency of their employment rights. This is a very common misconception that loses marks.</p>", "question": "How do the employment rights of part-time workers compare to full-time workers?", "options": ["They are exactly the same", "Part-time workers have fewer rights because they work fewer hours", "Part-time workers only gain full rights after one year", "Part-time workers have rights only if on a permanent contract"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the common misconception, stating part-time employees have exactly the same employment rights as full-time workers."}'::jsonb),
('business:3-2-organisational-structures:misc:651f4d59', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A wide span of control means a manager has few people to supervise.</p><p><strong>✅ The correct idea:</strong> A WIDE span means a manager has MANY subordinates reporting to them directly. A NARROW span means fewer subordinates. Wide span = flat structure; narrow span = tall structure. Students frequently confuse these.</p>", "question": "What does a WIDE span of control mean for a manager?", "options": ["The manager has very few people to supervise", "The manager has many direct-reporting subordinates", "The manager works in a tall structure", "The manager has no authority to make decisions"]}'::jsonb, '{"answer": 1, "explain": "The card explains a wide span means many direct subordinates (linked to flat structures), while a narrow span means few (linked to tall structures)."}'::jsonb),
('business:3-2-organisational-structures:misc:01385d56', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Delayering always makes a business better.</p><p><strong>✅ The correct idea:</strong> Delayering has BOTH benefits AND drawbacks. Benefits: saves wages, faster communication, more delegation. Drawbacks: fewer promotion opportunities for workers (reduces motivation), wider span of control may overwhelm remaining managers, and communication may actually get worse if the span becomes too wide. Evaluation is always required.</p>", "question": "Which statement best reflects the mark-scheme expectation when discussing delayering?", "options": ["It is always beneficial and should never be criticised", "It only affects wages and has no impact on communication", "It has both benefits and drawbacks, weighed together", "It always increases the number of management layers"]}'::jsonb, '{"answer": 2, "explain": "The card stresses delayering has both benefits (saved wages, faster communication) and drawbacks (fewer promotions, wider span risk), so evaluation is always required."}'::jsonb),
('business:3-2-organisational-structures:misc:8aacd69c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Span of control includes all the workers below a manager, not just direct reports.</p><p><strong>✅ The correct idea:</strong> Span of control ONLY counts the people who report DIRECTLY to that manager — not everyone in the layers below. For example, a Production Manager with 3 supervisors (each managing 20 workers) has a span of control of 3, not 63.</p>", "question": "A Production Manager has 3 supervisors, each managing 20 workers. What is the Production Manager''s span of control?", "options": ["60", "63", "20", "3"]}'::jsonb, '{"answer": 3, "explain": "Span of control only counts people reporting directly to that manager, so the Production Manager''s span is 3, not the 63 total workers below."}'::jsonb),
('business:3-2-organisational-structures:misc:5ccfead2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Flexible/home working is always beneficial for both businesses and workers.</p><p><strong>✅ The correct idea:</strong> Flexible/home working has BOTH benefits and drawbacks for BOTH parties. For workers: benefits include saving travel costs and flexibility, but drawbacks include social isolation and home distractions. For businesses: benefits include reduced office costs and productivity gains, but drawbacks include monitoring difficulties and technology costs. Never state it is ''always good.''</p>", "question": "Which statement correctly describes flexible/home working according to the notes?", "options": ["It has both benefits and drawbacks for workers and firms", "It is always beneficial for workers and businesses alike", "It benefits businesses but always harms workers", "It has no effect on office costs"]}'::jsonb, '{"answer": 0, "explain": "The card warns against saying flexible/home working is ''always good'', explaining it carries benefits and drawbacks for both workers and businesses."}'::jsonb),
('business:3-2-organisational-structures:misc:91861ca5', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The chain of command and the span of control are the same concept.</p><p><strong>✅ The correct idea:</strong> They are different. The CHAIN OF COMMAND is the LINE of authority from top to bottom (vertical path of instructions). The SPAN OF CONTROL is the NUMBER of subordinates one manager has (horizontal count). Confusing these terms in exam answers loses marks.</p>", "question": "What is the key difference between chain of command and span of control?", "options": ["They are different names for the same concept", "Chain of command is the line of authority; span is the number of subordinates", "Chain of command counts subordinates; span of control shows the line of authority", "Span of control only applies to flat structures"]}'::jsonb, '{"answer": 1, "explain": "The card distinguishes chain of command (the vertical path of authority) from span of control (the horizontal count of direct subordinates)."}'::jsonb),
('business:3-2-organisational-structures:tips:703ecb75', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one benefit/drawback of a structure (3 marks)", "reading": "Structure: (U) Explain the benefit (e.g. ''faster communication in a flat structure''). (APP) Link to the specific business in the case study (e.g. ''this means Nessa can respond quickly to the needs in the six stores''). (AN) Show the business impact (e.g. ''this could reverse the declining sales revenue''). Always chain: feature → effect on THIS business → business consequence.", "question": "For a 3-mark ''analyse one benefit of a structure'' question, what should the answer chain together?", "options": ["Only a definition of the structure with no context", "Two unrelated advantages listed separately", "The feature, its link to the business, and the consequence", "A judgement on which structure is best without explanation"]}'::jsonb, '{"answer": 2, "explain": "The tip explains the answer should chain: feature → effect on THIS business → business consequence (U, APP, AN)."}'::jsonb),
('business:3-2-organisational-structures:tips:e497f357', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Recommend which structure is most appropriate (3 marks)", "reading": "Make a clear recommendation (1 mark). Justify it with TWO contextual reasons from the case study for full marks. Example: ''Miles Ahead should use a flat structure (1) so that decisions can be made more quickly to reverse the fall in sales revenue since 2018 (CONT) and so that employees in the six stores feel trusted and motivated (CONT).''", "question": "To gain full marks recommending which structure is most appropriate (3 marks), what must the answer include beyond the recommendation itself?", "options": ["A list of every possible structure with no justification", "Only one reason, since two would be repetitive", "A calculation of the exact span of control", "Two contextual reasons justifying the choice made"]}'::jsonb, '{"answer": 3, "explain": "The tip states a clear recommendation (1 mark) must be justified with TWO contextual reasons from the case study for full marks."}'::jsonb),
('business:3-2-organisational-structures:tips:7c982c18', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — State one advantage/disadvantage of a way of working (1 mark)", "reading": "These short questions appear very frequently. Make sure you know ONE clear advantage AND disadvantage of: temporary working, flexible working, working from home, and zero-hours contracts — from BOTH the business AND the worker perspective. Never write ''saves money'' without specifying what costs are saved.", "question": "For a 1-mark ''state one advantage/disadvantage'' question about a way of working, what should be avoided?", "options": ["Writing ''saves money'' without specifying what costs are saved", "Naming a specific way of working such as flexible working", "Giving the answer from the business''s perspective", "Keeping the answer short and direct"]}'::jsonb, '{"answer": 0, "explain": "The tip warns never to write ''saves money'' without specifying what costs are actually saved."}'::jsonb),
('business:3-2-organisational-structures:tips:eb02fc8d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "7-Mark Evaluate Question — Evaluate whether a business should continue with a way of working", "reading": "Structure: APP x2 (use case study evidence twice — e.g. specific staff numbers, shift lengths). AN x2 (show the business impact of each point). EVAL x3 (judgement: should they continue? + 2 justified reasons using context). For JD Wetherspoon: link flexible contracts to cost control AND the staff shortage of 6,000 workers.", "question": "What is the recommended mark-scheme structure for a 7-mark ''evaluate whether to continue with a way of working'' question?", "options": ["Only a definition followed by one example", "APP x2, AN x2, EVAL x3", "One long paragraph with no clear structure", "K x1, U x1, with no application or evaluation"]}'::jsonb, '{"answer": 1, "explain": "The tip specifies structuring the answer as APP x2 (case study evidence), AN x2 (business impact), then EVAL x3 (judgement and two justified reasons)."}'::jsonb),
('business:3-2-organisational-structures:tips:3de6247f', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "9-Mark Discuss Question — Discuss whether to change organisational structure (9 marks)", "reading": "For Beautiful Buds: K (define delayering) → U (explain the process) → APP x2 (use the NUMBERS: £600k + £700k saving, £300k extra supervisor costs, £200k redundancy) → AN x2 (show business impact of savings AND risks) → EVAL x3 (overall judgement with net saving of £1m per year, long-term vs short-term). ALWAYS use the specific figures provided.", "question": "For the 9-mark ''discuss whether to change organisational structure'' question on Beautiful Buds, why is it important to use the specific figures (£600k, £700k, £300k, £200k)?", "options": ["Because the figures are not actually relevant to the answer", "Because only the final net saving figure needs to be mentioned", "Because APP marks need the case study numbers as evidence", "Because K marks require quoting numbers instead of definitions"]}'::jsonb, '{"answer": 2, "explain": "The tip stresses the APP x2 stage must use the specific numbers provided (savings and costs) to gain application marks, alongside K, U, AN and EVAL."}'::jsonb),
('business:3-2-organisational-structures:tips:09b82c5d', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Calculation Warning — Span of control calculations", "reading": "Span of control = ONLY direct reports. If a Production Manager has 3 supervisors, span = 3 (not 3 + 20×3 = 63). Mean average span: add up ALL subordinates across ALL managers, then divide by the number of managers. For POD Ltd: 46 total subordinates + 5 managers = 51 total. 6 managers total. 51 ÷ 6 = 8.5.", "question": "How is the mean average span of control calculated across a business?", "options": ["Divide the number of managers by the number of layers", "Add together the spans of only the most senior managers", "Multiply the number of layers by the number of subordinates", "Add subordinates across managers, then divide by total"]}'::jsonb, '{"answer": 3, "explain": "The tip explains the mean average span is found by adding all subordinates across all managers, then dividing by the number of managers, as shown in the POD Ltd example (51 ÷ 6 = 8.5)."}'::jsonb),
('business:3-2-organisational-structures:tips:fb175812', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Always evaluate delayering with BOTH sides", "reading": "Never say delayering is simply ''good because it saves money.'' Examiners expect both sides: savings vs. motivation risk (no promotion opportunities), faster communication vs. potential overload of remaining managers. Use the specific financial figures (e.g. £60,000 saving for Leigh Hire) for application marks. Conclude with a justified judgement.", "question": "According to the examiner warning, why should you never simply say delayering is ''good because it saves money''?", "options": ["Examiners expect both sides weighed, like savings versus lost promotions", "Because delayering never actually saves any money", "Because only application marks are available for this topic", "Because savings should never be mentioned in an answer about delayering"]}'::jsonb, '{"answer": 0, "explain": "The warning states examiners expect both sides — savings vs motivation risk and faster communication vs potential manager overload — followed by a justified judgement."}'::jsonb),
('business:3-2-organisational-structures:tips:f1de4748', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'tips', 'mcq', 1, '{"readingTitle": "Key Examiner Warning — Do NOT say part-time workers have fewer rights", "reading": "This is repeatedly flagged by examiners. Part-time workers have EXACTLY THE SAME employment rights as full-time workers. Writing otherwise will lose marks. Similarly, zero-hours workers cannot be paid below the minimum wage — a common misconception. Discrimination laws apply to ALL workers regardless of contract type.", "question": "Besides the part-time rights misconception, what other common error does this examiner warning highlight about zero-hours workers?", "options": ["The mistaken belief that zero-hours workers have no contract at all", "The mistaken belief they can be paid below minimum wage", "The mistaken belief that zero-hours workers cannot be dismissed", "The mistaken belief that zero-hours contracts are illegal in the UK"]}'::jsonb, '{"answer": 1, "explain": "The warning notes zero-hours workers cannot legally be paid below minimum wage, correcting a common misconception, and that discrimination laws apply to all workers regardless of contract type."}'::jsonb),
('business:3-2-organisational-structures:fib:8be468d1', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "The number of subordinates that report directly to a manager is called the _____ of control. A tall structure has a _____ span of control.", "blankOptions": {"B1": ["control", "tall", "span", "flat"], "B2": ["narrow", "delayering", "space", "control"]}}'::jsonb, '{"blanks": {"B1": "span", "B2": "narrow"}}'::jsonb),
('business:3-2-organisational-structures:fib:29169d6e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "When a business removes layers from its structure it is called _____, which usually saves _____ and speeds up communication.", "blankOptions": {"B1": ["part-time", "narrow", "delayering", "boss"], "B2": ["control", "money", "creative", "tall"]}}'::jsonb, '{"blanks": {"B1": "delayering", "B2": "money"}}'::jsonb),
('business:3-2-organisational-structures:fib:7f90fca2', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "A _____ structure has few layers and a wide span of control, making it suited to _____ businesses where fast communication matters.", "blankOptions": {"B1": ["delayering", "delegation", "span", "flat"], "B2": ["tall", "space", "wide", "creative"]}}'::jsonb, '{"blanks": {"B1": "flat", "B2": "creative"}}'::jsonb),
('business:3-2-organisational-structures:fib:d0eb00bb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "Full-time working means working _____ hours or more per week, while part-time workers have the _____ employment rights as full-time workers.", "blankOptions": {"B1": ["creative", "35", "flexible", "layers"], "B2": ["span", "delayering", "flat", "same"]}}'::jsonb, '{"blanks": {"B1": "35", "B2": "same"}}'::jsonb),
('business:3-2-organisational-structures:fib:0eda7d01', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "Working from home saves businesses money on office _____ and can increase worker _____, but makes it harder to monitor staff.", "blankOptions": {"B1": ["tall", "narrow", "35", "space"], "B2": ["same", "holiday", "productivity", "flexible"]}}'::jsonb, '{"blanks": {"B1": "space", "B2": "productivity"}}'::jsonb),
('business:3-2-organisational-structures:fib:30279e8e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'fib', 'fib', 2, '{"question": "A self-employed worker earns no _____ pay or sick pay from an employer, but benefits from being their own _____ and potentially earning more.", "blankOptions": {"B1": ["control", "holiday", "money", "layers"], "B2": ["flexible", "productivity", "space", "boss"]}}'::jsonb, '{"blanks": {"B1": "holiday", "B2": "boss"}}'::jsonb),
('business:3-2-organisational-structures:match:55ef407c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Span of control”?", "options": ["The path of authority along which instructions are passed, from the CEO downwards", "The number of subordinates who report directly to a manager", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible", "When a business reduces the number of layers in its organisational structure, making it flatter"]}'::jsonb, '{"answer": 1, "explain": "“Span of control” means: The number of subordinates who report directly to a manager"}'::jsonb),
('business:3-2-organisational-structures:match:2da57c3e', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Chain of command”?", "options": ["The path of authority along which instructions are passed, from the CEO downwards", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible", "When a business reduces the number of layers in its organisational structure, making it flatter", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses"]}'::jsonb, '{"answer": 0, "explain": "“Chain of command” means: The path of authority along which instructions are passed, from the CEO downwards"}'::jsonb),
('business:3-2-organisational-structures:match:d697549c', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Delegation”?", "options": ["When a business reduces the number of layers in its organisational structure, making it flatter", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses"]}'::jsonb, '{"answer": 1, "explain": "“Delegation” means: The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible"}'::jsonb),
('business:3-2-organisational-structures:match:2920587b', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Delayering”?", "options": ["An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses", "When a business reduces the number of layers in its organisational structure, making it flatter", "An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice"]}'::jsonb, '{"answer": 1, "explain": "“Delayering” means: When a business reduces the number of layers in its organisational structure, making it flatter"}'::jsonb),
('business:3-2-organisational-structures:match:905cee20', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Tall structure”?", "options": ["An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "Working part of the time at home and part of the time in an office", "An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses"]}'::jsonb, '{"answer": 3, "explain": "“Tall structure” means: An organisational structure with many layers and a narrow span of control, suited to large or non-creative businesses"}'::jsonb),
('business:3-2-organisational-structures:match:e111f824', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Flat structure”?", "options": ["A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses", "Working part of the time at home and part of the time in an office", "The number of subordinates who report directly to a manager"]}'::jsonb, '{"answer": 1, "explain": "“Flat structure” means: An organisational structure with few layers and a wide span of control, suited to creative or smaller businesses"}'::jsonb),
('business:3-2-organisational-structures:match:aa213dfb', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Zero-hours contract”?", "options": ["Working part of the time at home and part of the time in an office", "A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice", "The number of subordinates who report directly to a manager", "The path of authority along which instructions are passed, from the CEO downwards"]}'::jsonb, '{"answer": 1, "explain": "“Zero-hours contract” means: A contract where the worker is not guaranteed any hours and is called in when needed, sometimes at short notice"}'::jsonb),
('business:3-2-organisational-structures:match:a9114858', 'business', 'business:3-2-organisational-structures', '3.2 Organisational Structures', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Hybrid working”?", "options": ["Working part of the time at home and part of the time in an office", "The number of subordinates who report directly to a manager", "The path of authority along which instructions are passed, from the CEO downwards", "The process where a manager gives a subordinate authority to make certain decisions, while the manager remains ultimately responsible"]}'::jsonb, '{"answer": 0, "explain": "“Hybrid working” means: Working part of the time at home and part of the time in an office"}'::jsonb),
('business:3-3-communication-in-business:exam:2a75cf14', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which of these statements is FALSE?", "options": ["Digital communication involves the electronic transfer of information", "Mobile phones, computers and tablets are ways in which information can be transferred electronically", "Digital communication is always better than non-digital communication such as meetings", "Digital communication has been a major force behind the globalisation of business activity"], "hint": "Look for the word ''always'' — this is usually the signal that a statement is too absolute to be true.", "starter": "Digital communication is not always better because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Digital communication is always better than non-digital communication</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This statement is false because non-digital methods such as face-to-face meetings have distinct advantages: immediate two-way feedback, body language, discussion, and problem-solving. Digital communication cannot always replicate these. The word ''always'' makes this an absolute claim that is clearly incorrect.</p></div>", "modelAnswer": ""}'::jsonb),
('business:3-3-communication-in-business:exam:1701df10', 'business', 'business:3-3-communication-in-business', '3.3 Communication in Business', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What is a benefit to a patient of receiving communication from their hospital doctor by email rather than by letter?", "options": ["Doctors receive confirmation of receipt when the email is opened", "Emails can contain hyperlinks to further information about treatments", "Emails save money by reducing stationery, printing, and postal costs", "Multiple medical appointments can be sent out at the same time"], "hint": "Think about this from the PATIENT''S perspective — what helps the patient, not the doctor or the hospital.", "starter": "A benefit to the patient of email over letter is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Emails can contain hyperlinks to further information about treatments</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This is the only option that benefits the PATIENT specifically. Hyperlinks allow patients to access additional information about their condition or treatment — which helps them understand their healthcare. Options A, C and D are benefits to the hospital/doctor, not the patient.</p></div>", "modelAnswer": ""}'::jsonb)
